// ---- Splatoon 荧光配色池（背景 & 签文卡各随机取一色，保证撞色不重复）----
// 每色带 hue 值用于判断"够不够撞"，避免背景与卡片颜色太接近。
const INK_COLORS = [
  { name: "荧光粉", hex: "#FF3E9A", hue: 330 },
  { name: "电光青", hex: "#1EE3CF", hue: 174 },
  { name: "毒液绿", hex: "#8BFF3E", hue: 95 },
  { name: "熔岩橙", hex: "#FF7A1A", hue: 27 },
  { name: "深海蓝", hex: "#3E6BFF", hue: 226 },
  { name: "葡萄紫", hex: "#B04BFF", hue: 276 },
  { name: "柠檬黄", hex: "#FFE83E", hue: 52 },
  { name: "珊瑚红", hex: "#FF4B4B", hue: 0 },
  { name: "湖光蓝", hex: "#3EE0FF", hue: 192 },
  { name: "洋红", hex: "#FF3ECB", hue: 315 },
  { name: "青柠", hex: "#3EFF9E", hue: 152 },
  { name: "蜜橘", hex: "#FFB03E", hue: 40 },
];

// 计算两个 hue 的环形距离（0-180）
function hueDist(a, b) {
  const d = Math.abs(a - b) % 360;
  return d > 180 ? 360 - d : d;
}

// 抽一对撞色：背景色 + 签文卡色，色相至少相差 70 度
function pickColorPair(rng) {
  const bg = INK_COLORS[Math.floor(rng() * INK_COLORS.length)];
  const candidates = INK_COLORS.filter((c) => hueDist(c.hue, bg.hue) >= 70);
  const card = candidates[Math.floor(rng() * candidates.length)] || INK_COLORS[0];
  return { bg, card };
}

