// ---- 加权随机 ----
function weightedRank(rng) {
  const total = RANKS.reduce((s, r) => s + r.weight, 0);
  let n = rng() * total;
  for (const r of RANKS) {
    if (n < r.weight) return r;
    n -= r.weight;
  }
  return RANKS[RANKS.length - 1];
}

// ---- 简易可复现随机数（用日期做种子可实现"每日一签"）----
function mulberry32(seed) {
  return function () {
    seed |= 0;
    seed = (seed + 0x6d2b79f5) | 0;
    let t = Math.imul(seed ^ (seed >>> 15), 1 | seed);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

function pick(arr, rng) {
  return arr[Math.floor(rng() * arr.length)];
}
function pickTwo(arr, rng) {
  const a = pick(arr, rng);
  let b = pick(arr, rng);
  let guard = 0;
  while (b === a && guard++ < 10) b = pick(arr, rng);
  return [a, b];
}

// 为一个模式挑选它自己的等级（略微围绕总运势波动）
function modeTone(rng) {
  const r = rng();
  if (r < 0.34) return "good";
  if (r < 0.7) return "mid";
  return "bad";
}
const toneLabel = { good: "顺", mid: "平", bad: "逆" };
const toneColor = { good: "#4BE0D0", mid: "#E0D04B", bad: "#9B6BE0" };

// ---- 生成一支完整的签 ----
function drawFortune(seed) {
  const rng = mulberry32(seed);
  const rank = weightedRank(rng);
  const poem = pick(POEMS[rank.tone], rng);

  const modes = ["salmon", "anarchy", "xmatch"].map((k) => {
    const t = modeTone(rng);
    return {
      key: k,
      ...MODE_LINES[k],
      tone: t,
      text: pick(MODE_LINES[k][t], rng),
    };
  });

  const yi = pickTwo(YI_POOL, rng);
  const ji = pickTwo(JI_POOL, rng);
  const weapon = pick(LUCKY_WEAPONS, rng);
  const color = pick(LUCKY_COLORS, rng);
  const palette = pickColorPair(rng); // { bg, card } 两种撞色

  return { rank, poem, modes, yi, ji, weapon, color, palette, seed };
}

// ========================================================================
//  UI 组件
// ========================================================================

const STATE = { IDLE: "idle", SPINNING: "spinning", RESULT: "result" };

export default function SplatoonOmikuji() {
  const [phase, setPhase] = useState(STATE.IDLE);
  const [fortune, setFortune] = useState(null);
  const [dailyMode, setDailyMode] = useState(true); // 每日一签 vs 纯随机
  // 待机状态下的背景色，也随机取，让每次进来都不一样
  const [idlePair, setIdlePair] = useState(() => pickColorPair(Math.random));
  const spinTimer = useRef(null);

  const today = useMemo(() => {
    const d = new Date();
    return `${d.getFullYear()}.${String(d.getMonth() + 1).padStart(2, "0")}.${String(
      d.getDate()
    ).padStart(2, "0")}`;
  }, []);

  const dailySeed = useMemo(() => {
    const d = new Date();
    return d.getFullYear() * 10000 + (d.getMonth() + 1) * 100 + d.getDate();
  }, []);

  useEffect(() => () => clearTimeout(spinTimer.current), []);

  function handleDraw() {
    if (phase === STATE.SPINNING) return;
    setPhase(STATE.SPINNING);
    const seed = dailyMode ? dailySeed : Math.floor(Math.random() * 1e9);
    spinTimer.current = setTimeout(() => {
      setFortune(drawFortune(seed));
      setPhase(STATE.RESULT);
    }, 2200);
  }

  function reset() {
    setIdlePair(pickColorPair(Math.random)); // 回到扭蛋机换一套新配色
    setPhase(STATE.IDLE);
    setFortune(null);
  }

  // 当前生效的配色：抽到签就用签的配色，否则用待机配色
  const palette = fortune ? fortune.palette : idlePair;
  // 按主色相挑选最接近的预合成双色墨水背景图
  const bgImage = nearestInkBackground(palette.bg.hue);
  const rootStyle = {
    "--ink-bg": palette.bg.hex,
    "--ink-card": palette.card.hex,
    "--ink-bgimg": `url("${bgImage}")`,
  };

  return (
    <div className="omk-root" style={rootStyle}>
      <StyleTag />
      <div className="omk-inkbg" aria-hidden />

      <header className="omk-head">
        <div className="omk-date">{today}</div>
        <h1 className="omk-title">
          赛博<span>求签机</span>
        </h1>
        <p className="omk-sub">大厅扭蛋机 · 打工 / 真格 / X赛 当日运势</p>
      </header>

      {phase !== STATE.RESULT && (
        <MachineStage phase={phase} onDraw={handleDraw} />
      )}

      {phase === STATE.RESULT && fortune && (
        <FortuneCard fortune={fortune} onAgain={handleDraw} onReset={reset} />
      )}

      {phase !== STATE.RESULT && (
        <div className="omk-moderow">
          <button
            className={`omk-toggle ${dailyMode ? "on" : ""}`}
            onClick={() => setDailyMode(true)}
          >
            每日一签
          </button>
          <button
            className={`omk-toggle ${!dailyMode ? "on" : ""}`}
            onClick={() => setDailyMode(false)}
          >
            随缘连抽
          </button>
        </div>
      )}

      <footer className="omk-foot">
        娱乐向 · 运势仅供参考，胜负还看手速与配合
      </footer>
    </div>
  );
}

// ---- 双色墨水背景：按主色相挑选最接近的预合成背景图 ----
function nearestInkBackground(hue) {
  const keys = Object.keys(INK_BACKGROUNDS).map(Number);
  let best = keys[0];
  let bestD = 999;
  for (const k of keys) {
    let d = Math.abs(k - hue) % 360;
    if (d > 180) d = 360 - d;
    if (d < bestD) {
      bestD = d;
      best = k;
    }
  }
  return INK_BACKGROUNDS[best];
}


// ---- 扭蛋机舞台 ----
// 立体扭蛋球的配色（半透明荧光胶囊球，带高光）
// 生成一批球在玻璃罩内的摆放（用真实球图，尺寸偏小，罩里能看到十几个）
function makeBalls(rng, count) {
  const balls = [];
  for (let i = 0; i < count; i++) {
    // 初始位置：以玻璃罩中心为原点的极坐标，均匀铺满圆形罩内
    const ang = rng() * Math.PI * 2;
    const rad = Math.sqrt(rng()) * 40; // 0..40%，sqrt 让分布更均匀不聚中心
    balls.push({
      id: i,
      img: BALL_IMAGES[Math.floor(rng() * BALL_IMAGES.length)],
      // 初始位置（相对罩容器中心，%）
      cx: 50 + Math.cos(ang) * rad,
      cy: 52 + Math.sin(ang) * rad * 0.9,
      size: 20 + rng() * 8, // 小球，罩里能挤十几个
      // 绕圈用：各自的起始角、半径、以及自转
      swirlAng: ang,
      swirlRad: 8 + rng() * 20,
      selfSpin: rng() > 0.5 ? 1 : -1,
      dur: 2.4 + rng() * 1.2,
      delay: rng() * 0.3,
    });
  }
  return balls;
}

function MachineStage({ phase, onDraw }) {
  const spinning = phase === STATE.SPINNING;
  // 固定一批球（用固定种子，保证每次待机摆放一致）
  const balls = useMemo(() => makeBalls(mulberry32(20260701), 16), []);

  return (
    <div className="omk-stage">
      <div className={`machine ${spinning ? "spin" : ""}`}>
        {/* 机身图片（含玻璃罩、镀铬底座、投币旋钮、黄色墨渍） */}
        <img className="machine-img" src={MACHINE_IMG} alt="扭蛋机" draggable={false} />

        {/* 玻璃罩内的球（真实球图，叠在机身图之上，再由玻璃反光叠层压住做出景深） */}
        <div className="dome-balls">
          {balls.map((b) => (
            <img
              key={b.id}
              className="ball-img"
              src={b.img}
              alt=""
              draggable={false}
              style={{
                left: `${b.cx}%`,
                top: `${b.cy}%`,
                width: `${b.size}%`,
                "--dur": `${b.dur}s`,
                "--delay": `${b.delay}s`,
                "--swirl-x": `${Math.cos(b.swirlAng) * b.swirlRad}px`,
                "--swirl-y": `${Math.sin(b.swirlAng) * b.swirlRad}px`,
                "--spin": b.selfSpin,
              }}
            />
          ))}
        </div>

        {/* 玻璃反光叠层：压在球之上，制造"球在玻璃罩里"的景深 */}
        <div className="dome-glass" />

        {/* 拨杆旋钮高亮（转动时闪一下，暗示拨杆在动） */}
        <div className="knob-glow" />
      </div>

      <button className="omk-draw" onClick={onDraw} disabled={spinning}>
        {spinning ? "转动中…" : "投币抽签"}
      </button>
    </div>
  );
}

// ---- 签文结果卡 ----
function FortuneCard({ fortune, onAgain, onReset }) {
  const { rank, poem, modes, yi, ji, weapon, color, palette } = fortune;
  // 签文卡的主色用调色对里的 card 色（与背景撞色），等级色作为辅助点缀
  const cardHex = palette.card.hex;
  return (
    <div className="omk-result">
      <div
        className="card"
        style={{ "--accent": cardHex, "--glow": cardHex, "--rankc": rank.color }}
      >
        {/* 顶部等级 */}
        <div className="card-rank">
          <span className="rank-en">{rank.en}</span>
          <span className="rank-cn">{rank.name}</span>
        </div>

        {/* 签诗 */}
        <div className="card-poem">
          {poem.map((line, i) => (
            <p key={i} style={{ animationDelay: `${0.15 * i + 0.2}s` }}>
              {line}
            </p>
          ))}
        </div>

        <div className="card-divider" />

        {/* 三模式 */}
        <div className="card-modes">
          {modes.map((m) => (
            <div className="mode-row" key={m.key}>
              <div className="mode-head">
                <span className="mode-icon">{m.icon}</span>
                <span className="mode-label">{m.label}</span>
                <span className="mode-sub">{m.sub}</span>
                <span
                  className="mode-tone"
                  style={{ background: toneColor[m.tone] }}
                >
                  {toneLabel[m.tone]}
                </span>
              </div>
              <p className="mode-text">{m.text}</p>
            </div>
          ))}
        </div>

        <div className="card-divider" />

        {/* 宜忌 */}
        <div className="card-yiji">
          <div className="yiji-col yi">
            <span className="yiji-tag">宜</span>
            <span>{yi.join(" · ")}</span>
          </div>
          <div className="yiji-col ji">
            <span className="yiji-tag">忌</span>
            <span>{ji.join(" · ")}</span>
          </div>
        </div>

        {/* 幸运物 */}
        <div className="card-lucky">
          <div className="lucky-item">
            <span className="lucky-key">幸运武器</span>
            <span className="lucky-val">{weapon}</span>
          </div>
          <div className="lucky-item">
            <span className="lucky-key">幸运色</span>
            <span className="lucky-val">
              <i className="lucky-dot" style={{ background: color.hex }} />
              {color.name}
            </span>
          </div>
        </div>
      </div>

      <div className="omk-actions">
        <button className="omk-draw again" onClick={onAgain}>
          再抽一次
        </button>
        <button className="omk-draw ghost" onClick={onReset}>
          回到扭蛋机
        </button>
      </div>
    </div>
  );
}

// ========================================================================
//  样式
// ========================================================================
function StyleTag() {
  return (
    <style>{`
    @import url('https://fonts.googleapis.com/css2?family=Baloo+2:wght@600;800&family=Noto+Serif+SC:wght@600;700&family=Noto+Sans+SC:wght@400;700&display=swap');

    .omk-root{
      --pink:#FF5BA3; --cyan:#4BE0D0;
      --ink-bg:#FF3E9A; --ink-card:#1EE3CF; /* 由 JS 注入 */
      --ink-bgimg:none;                     /* 双色墨水背景图，由 JS 注入 */
      position:relative; min-height:100vh; width:100%;
      background:
        linear-gradient(160deg,
          color-mix(in srgb, var(--ink-bg) 30%, #0a0a1e) 0%,
          color-mix(in srgb, var(--ink-bg) 16%, #0a0a1e) 100%);
      color:#fff; font-family:'Noto Sans SC',system-ui,sans-serif;
      display:flex; flex-direction:column; align-items:center;
      padding:28px 18px 40px; box-sizing:border-box; overflow:hidden;
      transition:background 1s ease;
    }

    /* 整张双色墨水背景图（像对战场地那样），随配色切换 */
    .omk-inkbg{
      position:absolute; inset:0; z-index:0; pointer-events:none;
      background-image:var(--ink-bgimg);
      background-size:cover;
      background-position:center;
      opacity:.9;
      transition:opacity .8s ease;
      animation:inkbgIn .8s ease both;
    }
    /* 顶部/底部轻微压暗，让标题与内容更清晰 */
    .omk-inkbg::after{
      content:""; position:absolute; inset:0;
      background:linear-gradient(180deg,
        rgba(8,8,20,.55) 0%, rgba(8,8,20,.15) 22%,
        rgba(8,8,20,.15) 70%, rgba(8,8,20,.6) 100%);
    }
    @keyframes inkbgIn{ from{ opacity:0; } to{ opacity:.9; } }

    .omk-head{ text-align:center; z-index:2; position:relative; margin-bottom:8px; }
    .omk-date{
      font-family:'Baloo 2',sans-serif; letter-spacing:3px;
      color:#fff; font-weight:600; font-size:13px; opacity:.9;
      text-shadow:0 0 12px var(--ink-card);
    }
    .omk-title{
      font-family:'Baloo 2',sans-serif; font-weight:800;
      font-size:clamp(34px,9vw,56px); margin:2px 0 0; line-height:1;
      color:#fff; text-shadow:0 3px 0 rgba(0,0,0,.3), 0 0 30px rgba(0,0,0,.25);
    }
    .omk-title span{ color:#fff; text-shadow:0 3px 0 rgba(0,0,0,.3), 0 0 22px var(--ink-card); }
    .omk-sub{ margin:8px 0 0; font-size:13px; opacity:.85; letter-spacing:1px; text-shadow:0 1px 4px rgba(0,0,0,.4); }

    /* ---- 扭蛋机 ---- */
    .omk-stage{
      z-index:2; position:relative; display:flex; flex-direction:column; align-items:center;
      margin-top:26px;
    }
    /* ---- 扭蛋机（真实机身图 + 立体球体） ---- */
    .machine{
      position:relative; width:min(78vw, 320px); aspect-ratio:520/625;
      transform-origin:center bottom;
      filter:drop-shadow(0 20px 30px rgba(0,0,0,.5));
    }
    .machine.spin{ animation:machShake .3s ease-in-out infinite; }
    @keyframes machShake{
      0%,100%{ transform:rotate(0deg) translateY(0); }
      25%{ transform:rotate(-1.6deg) translateY(-2px); }
      75%{ transform:rotate(1.6deg) translateY(1px); }
    }
    .machine-img{
      position:relative; z-index:2; width:100%; height:100%;
      object-fit:contain; pointer-events:none; user-select:none;
    }

    /* 玻璃罩内的球容器：定位到机身图里玻璃罩的可见内部 */
    .dome-balls{
      position:absolute; z-index:3; left:22%; top:4%;
      width:56%; height:44%;
      border-radius:48% 48% 45% 45%;
      overflow:hidden;
    }
    .ball-img{
      position:absolute; transform:translate(-50%,-50%);
      filter:drop-shadow(0 2px 4px rgba(0,0,0,.35));
      will-change:transform; user-select:none; pointer-events:none;
    }
    /* 待机时球轻微上下浮动（像浮在里面） */
    .ball-img{ animation:ballFloat calc(var(--dur) * 1.6) ease-in-out infinite; animation-delay:var(--delay); }
    @keyframes ballFloat{
      0%,100%{ transform:translate(-50%,-50%) translateY(0) rotate(0deg); }
      50%{ transform:translate(-50%,-50%) translateY(-3px) rotate(calc(var(--spin) * 8deg)); }
    }
    /* 抽签时：每颗球绕自己的小圈打转，同时整个球群绕罩心转两三圈 */
    .machine.spin .dome-balls{
      animation:domeSwirl 2.2s cubic-bezier(.25,.6,.3,1) both;
    }
    /* 球群整体绕罩中心转 3 圈（1080°），先加速后减速，最后停住 */
    @keyframes domeSwirl{
      0%{ transform:rotate(0deg); }
      100%{ transform:rotate(1080deg); }
    }
    .machine.spin .ball-img{
      animation:ballOrbit var(--dur) linear infinite;
      animation-delay:var(--delay);
    }
    /* 每颗球自己也绕小圈 + 自转，叠加在球群大转上，看起来更翻滚 */
    @keyframes ballOrbit{
      0%{ transform:translate(-50%,-50%) translate(0,0) rotate(0deg); }
      25%{ transform:translate(-50%,-50%) translate(var(--swirl-x), var(--swirl-y)) rotate(calc(var(--spin) * 90deg)); }
      50%{ transform:translate(-50%,-50%) translate(0,0) rotate(calc(var(--spin) * 180deg)); }
      75%{ transform:translate(-50%,-50%) translate(calc(var(--swirl-x) * -1), calc(var(--swirl-y) * -1)) rotate(calc(var(--spin) * 270deg)); }
      100%{ transform:translate(-50%,-50%) translate(0,0) rotate(calc(var(--spin) * 360deg)); }
    }

    /* 玻璃反光叠层：压在球之上，制造"球在玻璃罩里"的景深 */
    .dome-glass{
      position:absolute; z-index:4; left:22%; top:4%;
      width:56%; height:44%; border-radius:48% 48% 45% 45%;
      pointer-events:none;
      background:
        radial-gradient(120% 80% at 30% 18%, rgba(255,255,255,.28), rgba(255,255,255,0) 45%),
        radial-gradient(80% 60% at 72% 12%, rgba(255,255,255,.18), rgba(255,255,255,0) 40%),
        linear-gradient(160deg, rgba(180,235,255,.10), rgba(0,0,0,.16));
      box-shadow:inset 0 -14px 26px rgba(0,0,0,.32), inset 0 8px 18px rgba(255,255,255,.08);
    }

    /* 投币旋钮位置的高亮：转动时闪烁，暗示拨杆在动。旋钮在机身图约(50%,65%) */
    .knob-glow{
      position:absolute; z-index:5; left:50%; top:64.5%;
      width:15%; height:12%; transform:translate(-50%,-50%);
      border-radius:50%; pointer-events:none; opacity:0;
    }
    .machine.spin .knob-glow{
      opacity:1;
      background:radial-gradient(circle, rgba(255,232,62,.55), rgba(255,232,62,0) 70%);
      animation:knobPulse .5s linear infinite;
    }
    @keyframes knobPulse{
      0%,100%{ transform:translate(-50%,-50%) scale(.85); opacity:.4; }
      50%{ transform:translate(-50%,-50%) scale(1.1); opacity:.9; }
    }

    .omk-draw{
      margin-top:30px; font-family:'Baloo 2','Noto Sans SC',sans-serif;
      font-weight:800; font-size:19px; letter-spacing:2px; color:#14142a;
      background:linear-gradient(#5affe4,#4BE0D0); border:none; cursor:pointer;
      padding:16px 44px; border-radius:40px; position:relative;
      box-shadow:0 6px 0 #1c9c92, 0 10px 24px rgba(75,224,208,.4);
      transition:transform .08s, box-shadow .08s;
    }
    .omk-draw:hover{ transform:translateY(-2px); box-shadow:0 8px 0 #1c9c92,0 14px 30px rgba(75,224,208,.5); }
    .omk-draw:active{ transform:translateY(4px); box-shadow:0 2px 0 #1c9c92; }
    .omk-draw:disabled{ opacity:.6; cursor:default; transform:none; box-shadow:0 6px 0 #1c9c92; }
    .omk-draw.again{ background:linear-gradient(#ff7db8,#FF5BA3); box-shadow:0 6px 0 #c1276f,0 10px 24px rgba(255,91,163,.4); }
    .omk-draw.ghost{ background:transparent; color:#fff; border:2px solid rgba(255,255,255,.3); box-shadow:none; }
    .omk-draw.ghost:active{ transform:translateY(1px); }

    .omk-moderow{ z-index:2; position:relative; display:flex; gap:10px; margin-top:26px; }
    .omk-toggle{
      background:rgba(0,0,0,.25); border:1.5px solid rgba(255,255,255,.25);
      color:rgba(255,255,255,.8); padding:8px 18px; border-radius:30px;
      font-family:'Noto Sans SC'; font-size:13px; cursor:pointer; transition:.15s;
      backdrop-filter:blur(3px);
    }
    .omk-toggle.on{ background:#fff; border-color:#fff; color:#14142a; font-weight:700; box-shadow:0 0 18px var(--ink-card); }

    /* ---- 结果卡 ---- */
    .omk-result{ z-index:2; position:relative; width:100%; max-width:440px; margin-top:20px;
      animation:cardIn .5s cubic-bezier(.2,.9,.3,1.2); }
    @keyframes cardIn{ from{ opacity:0; transform:translateY(30px) scale(.94); } to{ opacity:1; transform:none; } }

    .card{
      position:relative; border-radius:22px; padding:24px 22px 26px; overflow:hidden;
      background:
        linear-gradient(165deg,
          color-mix(in srgb, var(--accent) 30%, #12122a) 0%,
          color-mix(in srgb, var(--accent) 14%, #0d0d20) 100%);
      border:2px solid var(--accent);
      box-shadow:0 0 0 4px rgba(0,0,0,.25), 0 0 46px var(--glow), 0 22px 55px rgba(0,0,0,.55);
    }
    /* 卡片内的墨渍点缀 */
    .card::before{
      content:""; position:absolute; width:180px; height:180px; right:-50px; top:-40px;
      background:radial-gradient(circle, color-mix(in srgb,var(--accent) 55%, transparent) 0%, transparent 65%);
      pointer-events:none;
    }
    .card::after{
      content:""; position:absolute; width:150px; height:150px; left:-40px; bottom:-50px;
      background:radial-gradient(circle, color-mix(in srgb,var(--rankc) 45%, transparent) 0%, transparent 65%);
      pointer-events:none;
    }
    .card-rank{
      position:relative; z-index:1;
      display:flex; flex-direction:column; align-items:center; gap:2px; margin-bottom:14px;
    }
    .rank-en{
      font-family:'Baloo 2'; font-weight:800; font-size:15px; letter-spacing:5px;
      color:#fff; opacity:.85; text-shadow:0 0 12px var(--accent);
    }
    .rank-cn{
      font-family:'Noto Serif SC'; font-weight:700; font-size:46px; line-height:1;
      color:#fff; text-shadow:0 0 26px var(--glow), 0 2px 6px rgba(0,0,0,.5);
    }
    .card-poem, .card-modes, .card-yiji, .card-lucky, .card-divider{ position:relative; z-index:1; }
    .card-poem{
      display:flex; flex-direction:column; align-items:center; gap:5px; margin:10px 0 6px;
    }
    .card-poem p{
      font-family:'Noto Serif SC'; font-weight:600; font-size:19px; letter-spacing:4px;
      margin:0; color:#f2f2ff; opacity:0; animation:lineIn .5s forwards;
    }
    @keyframes lineIn{ from{ opacity:0; transform:translateY(8px);} to{ opacity:.95; transform:none;} }

    .card-divider{
      height:2px; margin:16px 4px; border-radius:2px;
      background:linear-gradient(90deg,transparent,var(--accent),transparent); opacity:.55;
    }

    .card-modes{ display:flex; flex-direction:column; gap:13px; }
    .mode-row{ }
    .mode-head{ display:flex; align-items:center; gap:7px; margin-bottom:4px; }
    .mode-icon{ font-size:16px; }
    .mode-label{ font-weight:700; font-size:15px; }
    .mode-sub{ font-size:10px; opacity:.45; letter-spacing:1px; }
    .mode-tone{
      margin-left:auto; font-size:12px; font-weight:700; color:#14142a;
      width:22px; height:22px; border-radius:50%; display:grid; place-items:center;
    }
    .mode-text{ margin:0; font-size:13px; line-height:1.65; opacity:.86; }

    .card-yiji{ display:flex; flex-direction:column; gap:8px; }
    .yiji-col{ display:flex; align-items:center; gap:10px; font-size:13.5px; }
    .yiji-tag{
      flex:none; width:26px; height:26px; border-radius:8px; display:grid; place-items:center;
      font-family:'Noto Serif SC'; font-weight:700; font-size:15px; color:#14142a;
    }
    .yi .yiji-tag{ background:var(--cyan); }
    .ji .yiji-tag{ background:#9B6BE0; }
    .yiji-col span:last-child{ opacity:.88; }

    .card-lucky{
      display:flex; gap:12px; margin-top:16px;
    }
    .lucky-item{
      flex:1; background:rgba(255,255,255,.05); border:1px solid rgba(255,255,255,.1);
      border-radius:12px; padding:10px 12px; display:flex; flex-direction:column; gap:3px;
    }
    .lucky-key{ font-size:10px; letter-spacing:2px; opacity:.5; }
    .lucky-val{ font-size:14px; font-weight:700; display:flex; align-items:center; gap:6px; }
    .lucky-dot{ width:13px; height:13px; border-radius:50%; box-shadow:0 0 8px currentColor; }

    .omk-actions{ display:flex; gap:12px; justify-content:center; margin-top:22px; }
    .omk-actions .omk-draw{ margin-top:0; font-size:16px; padding:14px 26px; }

    .omk-foot{ z-index:2; position:relative; margin-top:auto; padding-top:26px; font-size:11px; opacity:.55; letter-spacing:1px; text-shadow:0 1px 3px rgba(0,0,0,.5); }

    @media (prefers-reduced-motion: reduce){
      .machine.spin, .machine.spin *, .ball-img, .dome-balls, .card, .card-poem p, .omk-inkbg{ animation:none !important; }
      .card-poem p{ opacity:.95; }
      .omk-root{ transition:none; }
    }
    `}</style>
  );
}
